@page "/products"
@rendermode InteractiveServer
@using sv_cc9e394e1d734c4ab674f20da7331a43.Services
@inject CartState Cart

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row row-cols-1 row-cols-md-3 g-4 mt-2">
    @foreach (var product in _products)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text text-muted">@product.Description</p>
                    <p class="card-text fw-bold">@product.Price.ToString("C")</p>
                </div>
                <div class="card-footer">
                    <button class="btn btn-primary" @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private record Product(int Id, string Name, string Description, decimal Price);

    private readonly List<Product> _products =
    [
        new(1, "Wireless Mouse", "Ergonomic wireless mouse with USB receiver", 29.99m),
        new(2, "Mechanical Keyboard", "RGB backlit mechanical keyboard", 79.99m),
        new(3, "USB-C Hub", "7-in-1 USB-C hub with HDMI output", 49.99m),
        new(4, "Webcam HD", "1080p webcam with built-in microphone", 59.99m),
        new(5, "Monitor Stand", "Adjustable aluminum monitor stand", 39.99m),
        new(6, "Laptop Sleeve", "Neoprene sleeve for 15-inch laptops", 19.99m),
    ];

    private void AddToCart(Product product)
    {
        Cart.Add(product.Id, product.Name, product.Price);
    }
}

@page "/cart"
@rendermode InteractiveServer
@using sv_cc9e394e1d734c4ab674f20da7331a43.Services
@inject CartState Cart
@implements IDisposable

<PageTitle>Cart</PageTitle>

<h1>Your Cart</h1>

@if (!Cart.Items.Any())
{
    <p class="text-muted mt-3">Your cart is empty. <a href="products">Browse products</a></p>
}
else
{
    <table class="table mt-3">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in Cart.Items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>@item.Price.ToString("C")</td>
                    <td>@item.Quantity</td>
                    <td>@((item.Price * item.Quantity).ToString("C"))</td>
                    <td>
                        <button class="btn btn-danger btn-sm" @onclick="() => Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3" class="text-end fw-bold">Total:</td>
                <td class="fw-bold">@Cart.TotalPrice.ToString("C")</td>
                <td>
                    <button class="btn btn-outline-danger btn-sm" @onclick="ClearCart">
                        Clear All
                    </button>
                </td>
            </tr>
        </tfoot>
    </table>
}

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    private void Remove(int id) => Cart.Remove(id);

    private void ClearCart() => Cart.Clear();

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

